// // This module converts a 4-bit binary number to its corresponding Gray code representation.
module binary_to_gray (
  input [3:0] binary,
  output reg [3:0] gray
);

  always @* begin
    gray[3] = binary[3];
    gray[2] = binary[3] ^ binary[2];
    gray[1] = binary[2] ^ binary[1];
    gray[0] = binary[1] ^ binary[0];
  end

endmodule
